defmodule MyAppWeb.Plugs.XmlParser do
  @moduledoc """
  A custom Plug parser for XML content types that enforces
  a maximum body size and basic content-type validation.
  """
  @behaviour Plug.Parsers

  # 1 MB max for XML payloads
  @max_body_length 1_048_576

  @impl true
  def init(opts), do: opts

  @impl true
  def parse(conn, "text", "xml", _headers, opts) do
    case Plug.Conn.read_body(conn, length: @max_body_length) do
      {:ok, body, conn} ->
        {:ok, %{"_xml" => body}, conn}

      {:more, _partial, conn} ->
        {:error, :too_large, conn}

      {:error, _reason} ->
        {:error, :bad_request, conn}
    end
  end

  def parse(conn, "application", "soap+xml", _headers, opts) do
    parse(conn, "text", "xml", _headers, opts)
  end

  def parse(conn, _type, _subtype, _headers, _opts) do
    {:next, conn}
  end
end

